<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Kanban Board</title>
  <style>
    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      padding: 24px;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
      background: #eef2f5;
      color: #1e293b;
    }

    .board-controls {
      display: flex;
      gap: 12px;
      max-width: 1200px;
      margin: 0 auto 24px auto;
    }

    #new-card {
      flex: 1;
      padding: 12px 16px;
      border: 1px solid #cbd5e1;
      border-radius: 10px;
      font-size: 1rem;
      outline: none;
    }

    #new-card:focus {
      border-color: #2563eb;
      box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.15);
    }

    #add-card {
      padding: 12px 22px;
      border: none;
      border-radius: 10px;
      background: #2563eb;
      color: #fff;
      font-size: 1rem;
      font-weight: 600;
      cursor: pointer;
    }

    #add-card:hover {
      background: #1d4ed8;
    }

    .board {
      display: flex;
      gap: 24px;
      max-width: 1200px;
      margin: 0 auto;
      align-items: flex-start;
    }

    .column {
      flex: 1;
      min-width: 260px;
      background: #f8fafc;
      border-radius: 14px;
      box-shadow: 0 4px 6px rgba(0, 0, 0, 0.05);
      display: flex;
      flex-direction: column;
      max-height: calc(100vh - 140px);
    }

    .header {
      padding: 18px;
      font-weight: 700;
      font-size: 1.1rem;
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-bottom: 1px solid #e2e8f0;
    }

    .count {
      background: #e2e8f0;
      color: #475569;
      border-radius: 999px;
      padding: 3px 11px;
      font-size: 0.85rem;
      min-width: 28px;
      text-align: center;
    }

    .card-list {
      padding: 14px;
      display: flex;
      flex-direction: column;
      gap: 12px;
      min-height: 140px;
      overflow-y: auto;
    }

    .card {
      background: #fff;
      border: 1px solid #e2e8f0;
      border-radius: 12px;
      padding: 14px 16px;
      box-shadow: 0 2px 5px rgba(0, 0, 0, 0.06);
      cursor: grab;
      display: flex;
      justify-content: space-between;
      align-items: center;
      gap: 12px;
      transition: transform 0.1s ease, box-shadow 0.1s ease;
    }

    .card:active {
      cursor: grabbing;
    }

    .card-title {
      line-height: 1.45;
      word-break: break-word;
    }

    .card-del {
      border: none;
      background: transparent;
      color: #94a3b8;
      font-size: 1.4rem;
      line-height: 1;
      padding: 0 4px;
      cursor: pointer;
    }

    .card-del:hover {
      color: #ef4444;
    }

    @media (max-width: 800px) {
      .board {
        flex-direction: column;
      }
      .column {
        max-height: none;
        width: 100%;
      }
    }
  </style>
</head>
<body>

  <div class="board-controls">
    <input type="text" id="new-card" placeholder="Enter a new task..." autocomplete="off">
    <button id="add-card">Add Card</button>
  </div>

  <div class="board">
    <div class="column" id="col-todo">
      <div class="header">To Do <span class="count">0</span></div>
      <div class="card-list"></div>
    </div>
    <div class="column" id="col-doing">
      <div class="header">Doing <span class="count">0</span></div>
      <div class="card-list"></div>
    </div>
    <div class="column" id="col-done">
      <div class="header">Done <span class="count">0</span></div>
      <div class="card-list"></div>
    </div>
  </div>

  <script>
    (function () {
      const STORAGE_KEY = 'kanban-board-state';
      let nextId = 1;

      function storageGet() {
        try {
          return localStorage.getItem(STORAGE_KEY);
        } catch (e) {
          return null;
        }
      }

      function storageSet(value) {
        try {
          localStorage.setItem(STORAGE_KEY, value);
        } catch (e) {
          // Storage may be unavailable; app continues to work.
        }
      }

      function updateCounts() {
        document.querySelectorAll('.column').forEach(col => {
          const count = col.querySelectorAll('.card').length;
          col.querySelector('.count').textContent = count;
        });
      }

      function saveState() {
        const state = { cards: [] };
        document.querySelectorAll('.column').forEach(col => {
          const colId = col.id;
          col.querySelectorAll('.card').forEach(card => {
            const title = card.querySelector('.card-title').textContent;
            state.cards.push({ id: card.id, title, colId });
          });
        });
        storageSet(JSON.stringify(state));
      }

      function createCard(title, id) {
        const cardId = id || 'card-' + (nextId++);
        const card = document.createElement('div');
        card.className = 'card';
        card.id = cardId;
        card.draggable = true;

        const titleSpan = document.createElement('span');
        titleSpan.className = 'card-title';
        titleSpan.textContent = title;

        const delBtn = document.createElement('button');
        delBtn.className = 'card-del';
        delBtn.type = 'button';
        delBtn.setAttribute('aria-label', 'Delete card');
        delBtn.textContent = '×';
        delBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          card.remove();
          updateCounts();
          saveState();
        });

        card.appendChild(titleSpan);
        card.appendChild(delBtn);

        card.addEventListener('dragstart', (e) => {
          e.dataTransfer.setData('text/plain', card.id);
          e.dataTransfer.effectAllowed = 'move';
        });

        return card;
      }

      function addCard() {
        const input = document.getElementById('new-card');
        const title = input.value.trim();
        if (!title) return;

        const todoList = document.querySelector('#col-todo .card-list');
        todoList.appendChild(createCard(title));
        input.value = '';
        input.focus();
        updateCounts();
        saveState();
      }

      function loadState() {
        const saved = storageGet();
        if (!saved) return;

        try {
          const state = JSON.parse(saved);
          if (!state.cards || !Array.isArray(state.cards)) return;

          state.cards.forEach(c => {
            const match = /^card-(\d+)$/.exec(c.id || '');
            if (match) {
              nextId = Math.max(nextId, parseInt(match[1], 10) + 1);
            }
          });

          state.cards.forEach(c => {
            const col = document.getElementById(c.colId);
            if (col) {
              col.querySelector('.card-list').appendChild(createCard(c.title, c.id));
            }
          });
        } catch (e) {
          console.error('Failed to load board state', e);
        }
      }

      document.getElementById('add-card').addEventListener('click', addCard);
      document.getElementById('new-card').addEventListener('keydown', (e) => {
        if (e.key === 'Enter') addCard();
      });

      document.querySelectorAll('.column').forEach(col => {
        col.addEventListener('dragover', (e) => {
          e.preventDefault();
          e.dataTransfer.dropEffect = 'move';
        });

        col.addEventListener('drop', (e) => {
          e.preventDefault();
          const cardId = e.dataTransfer.getData('text/plain');
          const card = document.getElementById(cardId);
          if (!card) return;

          col.querySelector('.card-list').appendChild(card);
          updateCounts();
          saveState();
        });
      });

      loadState();
      updateCounts();
    })();
  </script>

</body>
</html>
